use anyhow::Result;
use hydro_deploy::Deployment;
use hydro_lang::deploy::TrybuildHost;
use hydro_lang::{q, Location};
use serde::{Deserialize, Serialize};
use tokio::main;

struct Server {}
struct Worker {}

#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct ChatMsg {
    pub content: String,
}

#[main]
async fn main() -> Result<()> {
    let mut deployment = Deployment::new();
    let flow = hydro_lang::FlowBuilder::new();

    // Create a server process and worker cluster
    let server = flow.process::<Server>();
    let workers = flow.cluster::<Worker>();

    // Define the dataflow: workers send messages to server
    let worker_messages = workers
        .source_iter(q!(|_| [
            ChatMsg { content: "Hello from worker 1".to_string() },
            ChatMsg { content: "Hello from worker 2".to_string() },
            ChatMsg { content: "Hello from worker 3".to_string() }
        ]))
        .map(q!(|msg| {
            println!("Worker sending: {}", msg.content);
            msg
        }));

    // Server receives messages from workers
    let server_inbox = server.source_stream(worker_messages.send_bincode_interleaved());

    server_inbox
        .for_each(q!(|msg: ChatMsg| {
            println!("Server received: {}", msg.content);
        }));

    // Server sends responses back to workers
    let server_responses = server
        .source_iter(q!(|_| [
            ChatMsg { content: "ACK from server".to_string() }
        ]))
        .map(q!(|msg| {
            println!("Server sending response: {}", msg.content);
            msg
        }));

    // Workers receive responses from server
    let worker_responses = workers.source_stream(server_responses.send_bincode_interleaved());

    worker_responses
        .for_each(q!(|msg: ChatMsg| {
            println!("Worker received response: {}", msg.content);
        }));

    // Deploy the cluster with server and 3 workers
    let _nodes = flow
        .with_default_optimize()
        .with_process(&server, TrybuildHost::new(deployment.Localhost()))
        .with_cluster(
            &workers,
            (0..3).map(|_| TrybuildHost::new(deployment.Localhost())),
        )
        .deploy(&mut deployment);

    // Run until Ctrl+C
    deployment.run_ctrl_c().await?;
    Ok(())
}

use anyhow::Result;
use hydro_deploy::Deployment;
use hydro_lang::deploy::TrybuildHost;
use hydro_lang::{q, Location};
use serde::{Deserialize, Serialize};
use tokio::main;

struct Server {}
struct Worker {}

#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct ChatMsg {
    pub content: String,
}

#[main]
async fn main() -> Result<()> {
    let mut deployment = Deployment::new();
    let flow = hydro_lang::FlowBuilder::new();

    // Create a server process and worker cluster
    let server = flow.process::<Server>();
    let workers = flow.cluster::<Worker>();

    // Define the dataflow: workers send messages to server
    let worker_messages = workers
        .source_iter(q!(move |_cluster, _| {
            vec![
                ChatMsg { content: "Hello from worker 1".to_string() },
                ChatMsg { content: "Hello from worker 2".to_string() },
                ChatMsg { content: "Hello from worker 3".to_string() }
            ]
        }))
        .map(q!(|msg| {
            println!("Worker sending: {}", msg.content);
            msg
        }));

    // Server receives messages from workers
    let server_inbox = server.source_stream(worker_messages.send_bincode_interleaved());

    server_inbox
        .for_each(q!(|msg: ChatMsg| {
            println!("Server received: {}", msg.content);
        }));

    // Server sends responses back to workers
    let server_responses = server
        .source_iter(q!(move |_process, _| {
            vec![
                ChatMsg { content: "ACK from server".to_string() }
            ]
        }))
        .map(q!(|msg| {
            println!("Server sending response: {}", msg.content);
            msg
        }));

    // Workers receive responses from server
    let worker_responses = workers.source_stream(server_responses.send_bincode_interleaved());

    worker_responses
        .for_each(q!(|msg: ChatMsg| {
            println!("Worker received response: {}", msg.content);
        }));

    // Deploy the cluster with server and 3 workers
    let _nodes = flow
        .with_default_optimize()
        .with_process(&server, TrybuildHost::new(deployment.Localhost()))
        .with_cluster(
            &workers,
            (0..3).map(|_| TrybuildHost::new(deployment.Localhost())),
        )
        .deploy(&mut deployment);

    // Run until Ctrl+C
    deployment.run_ctrl_c().await?;
    Ok(())
}
